content:
{
  "sentences": [
    {
      "text": "我現在每天中午吃午餐。",
      "pinyin": "Wǒ xiànzài měitiān zhōngwǔ chī wǔcān.",
      "pinyin_numeric": "wo3 xian4zai4 mei3tian1 zhong1wu3 chi1 wu3can1.",
      "translation_en": "I now eat lunch every day at noon.",
      "translation_ko": "저는 지금 매일 점심에 점심을 먹습니다."
    },
    {
      "text": "他現在晚上在家看電視。",
      "pinyin": "Tā xiànzài wǎnshàng zài jiā kàn diànshì.",
      "pinyin_numeric": "ta1 xian4zai4 wan3shang4 zai4 jia1 kan4 dian4shi4.",
      "translation_en": "He now watches TV at home in the evening.",
      "translation_ko": "그는 지금 저녁에 집에서 텔레비전을 봅니다."
    },
    {
      "text": "我們現在早上七點起床。",
      "pinyin": "Wǒmen xiànzài zǎoshang qī diǎn qǐchuáng.",
      "pinyin_numeric": "wo3men xian4zai4 zao3shang4 qi1 dian3 qi3chuang2.",
      "translation_en": "We now get up at seven in the morning.",
      "translation_ko": "우리는 지금 아침 7시에 일어납니다."
    },
    {
      "text": "她現在下午三點上班。",
      "pinyin": "Tā xiànzài xiàwǔ sān diǎn shàngbān.",
      "pinyin_numeric": "ta1 xian4zai4 xia4wu3 san1 dian3 shang4ban1.",
      "translation_en": "She now goes to work at three in the afternoon.",
      "translation_ko": "그녀는 지금 오후 3시에 출근합니다."
    },
    {
      "text": "我現在晚上十點睡覺。",
      "pinyin": "Wǒ xiànzài wǎnshàng shí diǎn shuìjiào.",
      "pinyin_numeric": "wo3 xian4zai4 wan3shang4 shi2 dian3 shui4jiao4.",
      "translation_en": "I now go to sleep at ten in the evening.",
      "translation_ko": "저는 지금 저녁 10시에 잡니다."
    },
    {
      "text": "他現在中午十二點下課。",
      "pinyin": "Tā xiànzài zhōngwǔ shí'èr diǎn xiàkè.",
      "pinyin_numeric": "ta1 xian4zai4 zhong1wu3 shi2'er4 dian3 xia4ke4.",
      "translation_en": "He now finishes class at twelve noon.",
      "translation_ko": "그는 지금 정오 12시에 수업이 끝납니다."
    },
    {
      "text": "我們現在下午五點下班。",
      "pinyin": "Wǒmen xiànzài xiàwǔ wǔ diǎn xiàbān.",
      "pinyin_numeric": "wo3men xian4zai4 xia4wu3 wu3 dian3 xia4ban1.",
      "translation_en": "We now get off work at five in the afternoon.",
      "translation_ko": "우리는 지금 오후 5시에 퇴근합니다."
    },
    {
      "text": "她現在早上八點上課。",
      "pinyin": "Tā xiànzài zǎoshang bā diǎn shàngkè.",
      "pinyin_numeric": "ta1 xian4zai4 zao3shang4 ba1 dian3 shang4ke4.",
      "translation_en": "She now goes to class at eight in the morning.",
      "translation_ko": "그녀는 지금 아침 8시에 수업을 듣습니다."
    },
    {
      "text": "我現在晚上七點吃晚餐。",
      "pinyin": "Wǒ xiànzài wǎnshàng qī diǎn chī wǎncān.",
      "pinyin_numeric": "wo3 xian4zai4 wan3shang4 qi1 dian3 chi1 wan3can1.",
      "translation_en": "I now eat dinner at seven in the evening.",
      "translation_ko": "저는 지금 저녁 7시에 저녁을 먹습니다."
    },
    {
      "text": "他現在每天下午散步。",
      "pinyin": "Tā xiànzài měitiān xiàwǔ sànbù.",
      "pinyin_numeric": "ta1 xian4zai4 mei3tian1 xia4wu3 san4bu4.",
      "translation_en": "He now takes a walk every afternoon.",
      "translation_ko": "그는 지금 매일 오후에 산책합니다."
    }
  ]
}
